    let dir = args.dir.clone().unwrap_or_else(|| {
        cfg.workspace_dir
            .clone()
            .map(pathbuf::from)
            .unwrap_or_else(|| std::env::current_dir().unwrap_or_else(|_| pathbuf::from(".")))
    });
